import React, { useEffect, useState } from "react";
import axios from "axios";


export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);

  useEffect(() => {
    cargarHistorial();
  }, []);

  const cargarHistorial = async () => {
    const res = await axios.get("http://localhost:5000/api/ventas/historial");
    setVentas(res.data);
  };

  return (
    <div className="container mt-4">
      <h3>📊 Historial de Ventas</h3>

      <table className="table table-bordered table-striped mt-3">
        <thead className="table-dark">
          <tr>
            <th>Factura</th>
            <th>Fecha</th>
            <th>Cliente</th>
            <th>Subtotal</th>
            <th>IVA</th>
            <th>Total</th>
          </tr>
        </thead>
        <tbody>
          {ventas.map(v => (
            <tr key={v.VentaID}>
              <td>{v.NumeroSecuencia}</td>
              <td>{new Date(v.Fecha).toLocaleString()}</td>
              <td>{v.Cliente}</td>
              <td>${v.Subtotal.toFixed(2)}</td>
              <td>${v.IVA.toFixed(2)}</td>
              <td className="fw-bold">${v.Total.toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
